// Initial implementation
function rememberMe(username, passwordHash) {
    if (document.getElementById('rememberMe').checked) {
        document.cookie = `username=${username}; max-age=2592000; path=/`;
        document.cookie = `passwordHash=${passwordHash}; max-age=2592000; path=/`;
    }
}

function autoLogin() {
    const usernameCookie = getCookie('username');
    const passwordHashCookie = getCookie('passwordHash');

    if (usernameCookie && passwordHashCookie) {
        // Simulate login
        console.log(`Auto-logging in as ${usernameCookie}`);
    }
}

function getCookie(name) {
    const value = `; ${document.cookie}`;
    const parts = value.split(`; ${name}=`);
    if (parts.length === 2) return parts.pop().split(';').shift();
}